#!/usr/bin/env python3
# brief — the project brief: every decision and its reasoning, oldest first.
import sys, json
from html import escape
ds = []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
    except Exception:
        continue
    if e.get("name") == "decision.made":
        ds.append(e.get("payload", {}) or {})
print("<!DOCTYPE html><html><head><meta charset='utf-8'><title>brief</title></head><body>")
print("<h1>project brief</h1>")
print("<p class='muted'>The decisions that shaped this system, and why — the reasoning, not just the conclusions. %d so far, oldest first. Add one: self run decision \"choice :: why :: instead-of\".</p>" % len(ds))
for i, d in enumerate(ds, 1):
    print("<div class='card'>")
    print("<h3>%d. %s</h3>" % (i, escape(d.get("choice", ""))))
    if d.get("why"):
        print("<p>%s</p>" % escape(d.get("why", "")))
    if d.get("rejected"):
        print("<p class='muted'>instead of: %s</p>" % escape(d.get("rejected", "")))
    print("</div>")
print("</body></html>")
